"/* ==========================================================================
   EnerThai Service Worker - Offline Caching
   ========================================================================== */

const CACHE_NAME = 'enerthai-v1';
const ASSETS_TO_CACHE = [
  'index.html',
  'products.html',
  'product.html',
  'calculator.html',
  'story.html',
  'science.html',
  'faq.html',
  'contact.html',
  'css/style.css',
  'css/pages.css',
  'js/main.js',
  'js/calculator.js',
  'manifest.json'
];

// Install Event - cache assets
self.addEventListener('install', (e) => {
  e.waitUntil(
    caches.open(CACHE_NAME)
      .then((cache) => {
        return cache.addAll(ASSETS_TO_CACHE);
      })
      .then(() => {
        return self.skipWaiting();
      })
  );
});

// Activate Event - clean old caches
self.addEventListener('activate', (e) => {
  e.waitUntil(
    caches.keys().then((keys) => {
      return Promise.all(
