    save(data) {
        localStorage.setItem(this.key, JSON.stringify(data));
        this.updateUI();
    },

    add(id, qty = 1) {
        const product = window.EnerThaiProducts[id];
        if (!product) return;

        let cart = this.get();
        const existingItem = cart.find(item => item.id === id);

        if (existingItem) {
            existingItem.qty += qty;
        } else {
            cart.push({
                id: product.id,
                name: product.name,
                price: product.price,
                purpose: product.purpose,
                imageGrad: product.imageGrad,
                qty: qty
            });
        }
        this.save(cart);
        this.openDrawer();
    },

    remove(id) {
        let cart = this.get();
        cart = cart.filter(item => item.id !== id);
        this.save(cart);
    },

    updateQty(id, delta) {
        let cart = this.get();
        const item = cart.find(item => item.id === id);
        if (item) {
            item.qty += delta;
            if (item.qty <= 0) {
                cart = cart.filter(i => i.id !== id);
            }
        }
        this.save(cart);
